import React, { useState } from 'react';
import { useUsers } from '../context/UserContext';
import AddUserForm from '../components/Users/AddUserForm';

function UserManagement() {
  const { users, deleteUser } = useUsers();
  const [showAddForm, setShowAddForm] = useState(false);
  const [filterRole, setFilterRole] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredUsers = users.filter(user => {
    const matchesRole = filterRole === 'all' || user.role === filterRole;
    const matchesSearch = user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.subject.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesRole && matchesSearch;
  });

  const stats = {
    total: users.length,
    admins: users.filter(u => u.role === 'admin').length,
    teachers: users.filter(u => u.role === 'teacher').length,
    active: users.filter(u => u.status === 'active').length
  };

  return (
    <div>
      {/* Header with Stats */}
      <div style={{ marginBottom: '30px' }}>
        <h2 style={{ fontSize: '28px', marginBottom: '20px' }}>User Management</h2>

        {/* Stats Cards */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: '20px',
          marginBottom: '30px'
        }}>
          <div style={{
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            padding: '20px',
            borderRadius: '15px',
            color: 'white',
            boxShadow: '0 10px 20px rgba(102, 126, 234, 0.3)'
          }}>
            <div style={{ fontSize: '14px', opacity: 0.9 }}>Total Users</div>
            <div style={{ fontSize: '36px', fontWeight: 'bold' }}>{stats.total}</div>
            <div style={{ fontSize: '12px', marginTop: '5px' }}>+2 this month</div>
          </div>

          <div style={{
            background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
            padding: '20px',
            borderRadius: '15px',
            color: 'white',
            boxShadow: '0 10px 20px rgba(240, 147, 251, 0.3)'
          }}>
            <div style={{ fontSize: '14px', opacity: 0.9 }}>Admins</div>
            <div style={{ fontSize: '36px', fontWeight: 'bold' }}>{stats.admins}</div>
            <div style={{ fontSize: '12px', marginTop: '5px' }}>System administrators</div>
          </div>

          <div style={{
            background: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
            padding: '20px',
            borderRadius: '15px',
            color: 'white',
            boxShadow: '0 10px 20px rgba(79, 172, 254, 0.3)'
          }}>
            <div style={{ fontSize: '14px', opacity: 0.9 }}>Teachers</div>
            <div style={{ fontSize: '36px', fontWeight: 'bold' }}>{stats.teachers}</div>
            <div style={{ fontSize: '12px', marginTop: '5px' }}>Faculty members</div>
          </div>

          <div style={{
            background: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)',
            padding: '20px',
            borderRadius: '15px',
            color: 'white',
            boxShadow: '0 10px 20px rgba(67, 233, 123, 0.3)'
          }}>
            <div style={{ fontSize: '14px', opacity: 0.9 }}>Active Users</div>
            <div style={{ fontSize: '36px', fontWeight: 'bold' }}>{stats.active}</div>
            <div style={{ fontSize: '12px', marginTop: '5px' }}>Currently active</div>
          </div>
        </div>

        {/* Action Bar */}
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '20px'
        }}>
          <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
            <select
              value={filterRole}
              onChange={(e) => setFilterRole(e.target.value)}
              style={{
                padding: '12px 20px',
                borderRadius: '8px',
                border: '2px solid #e0e0e0',
                fontSize: '14px',
                cursor: 'pointer',
                backgroundColor: 'white'
              }}
            >
              <option value="all">All Users</option>
              <option value="admin">Admins Only</option>
              <option value="teacher">Teachers Only</option>
            </select>
          </div>

          <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
            <div style={{ position: 'relative' }}>
              <input
                type="text"
                placeholder="Search users..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                style={{
                  padding: '12px 20px',
                  borderRadius: '8px',
                  border: '2px solid #e0e0e0',
                  width: '300px',
                  fontSize: '14px'
                }}
              />
            </div>

            <button
              onClick={() => setShowAddForm(true)}
              style={{
                padding: '12px 24px',
                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                color: 'white',
                border: 'none',
                borderRadius: '8px',
                fontSize: '16px',
                fontWeight: 'bold',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: '8px',
                boxShadow: '0 4px 6px rgba(102, 126, 234, 0.4)',
                transition: 'transform 0.2s'
              }}
              onMouseEnter={(e) => e.target.style.transform = 'translateY(-2px)'}
              onMouseLeave={(e) => e.target.style.transform = 'translateY(0)'}
            >
              Add New User
            </button>
          </div>
        </div>
      </div>

      {/* Users Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
        gap: '20px',
        padding: '10px 0'
      }}>
        {filteredUsers.map(user => (
          <div
            key={user.id}
            style={{
              background: 'white',
              borderRadius: '15px',
              padding: '20px',
              boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
              border: '1px solid #f0f0f0',
              transition: 'transform 0.2s, box-shadow 0.2s',
              cursor: 'pointer',
              position: 'relative',
              overflow: 'hidden'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-5px)';
              e.currentTarget.style.boxShadow = '0 10px 20px rgba(0,0,0,0.15)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = '0 4px 6px rgba(0,0,0,0.1)';
            }}
          >
            {/* Colored top bar based on role */}
            <div style={{
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              height: '6px',
              background: user.role === 'admin' 
                ? 'linear-gradient(90deg, #f093fb, #f5576c)'
                : 'linear-gradient(90deg, #4facfe, #00f2fe)'
            }}></div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
              {/* Avatar */}
              <div style={{
                width: '70px',
                height: '70px',
                borderRadius: '50%',
                background: user.role === 'admin' 
                  ? 'linear-gradient(135deg, #f093fb, #f5576c)'
                  : 'linear-gradient(135deg, #4facfe, #00f2fe)',
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                fontSize: '32px',
                color: 'white'
              }}>
                {user.avatar}
              </div>

              {/* User Info */}
              <div style={{ flex: 1 }}>
                <h3 style={{ margin: '0 0 5px 0', fontSize: '18px' }}>{user.name}</h3>
                <p style={{ margin: '0 0 5px 0', color: '#666', fontSize: '14px' }}>
                  {user.email}
                </p>
                <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                  <span style={{
                    padding: '4px 12px',
                    borderRadius: '20px',
                    fontSize: '12px',
                    fontWeight: 'bold',
                    background: user.role === 'admin' ? '#f093fb20' : '#4facfe20',
                    color: user.role === 'admin' ? '#f093fb' : '#4facfe',
                    border: `1px solid ${user.role === 'admin' ? '#f093fb40' : '#4facfe40'}`
                  }}>
                    {user.role === 'admin' ? 'Admin' : 'Teacher'}
                  </span>
                  <span style={{
                    padding: '4px 12px',
                    borderRadius: '20px',
                    fontSize: '12px',
                    background: '#f0f0f0',
                    color: '#666'
                  }}>
                    {user.age} yrs
                  </span>
                  <span style={{
                    padding: '4px 12px',
                    borderRadius: '20px',
                    fontSize: '12px',
                    background: '#f0f0f0',
                    color: '#666'
                  }}>
                    {user.gender}
                  </span>
                </div>
              </div>
            </div>

            {/* Subject and Join Date */}
            <div style={{
              marginTop: '15px',
              padding: '10px',
              background: '#f8f9fa',
              borderRadius: '10px',
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center'
            }}>
              <div>
                <span style={{ fontSize: '13px', color: '#666' }}>Subject:</span>
                <span style={{ marginLeft: '5px', fontWeight: 'bold', color: '#333' }}>
                  {user.subject}
                </span>
              </div>
              <div>
                <span style={{ fontSize: '13px', color: '#666' }}>Joined:</span>
                <span style={{ marginLeft: '5px', color: '#333' }}>
                  {new Date(user.joinDate).toLocaleDateString()}
                </span>
              </div>
            </div>

            {/* Action Buttons */}
            <div style={{
              marginTop: '15px',
              display: 'flex',
              gap: '10px',
              justifyContent: 'flex-end'
            }}>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  // Edit user
                }}
                style={{
                  padding: '8px 15px',
                  background: 'linear-gradient(135deg, #4facfe, #00f2fe)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '6px',
                  cursor: 'pointer',
                  fontSize: '13px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '5px'
                }}
              >
                Edit
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  if (window.confirm(`Delete ${user.name}?`)) {
                    deleteUser(user.id);
                  }
                }}
                style={{
                  padding: '8px 15px',
                  background: 'linear-gradient(135deg, #f093fb, #f5576c)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '6px',
                  cursor: 'pointer',
                  fontSize: '13px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '5px'
                }}
              >
                Delete
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Add User Form Modal */}
      {showAddForm && (
        <AddUserForm 
          onClose={() => setShowAddForm(false)}
          onSuccess={() => {
            setShowAddForm(false);
            // Show success message
          }}
        />
      )}
    </div>
  );
}

export default UserManagement;
